import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"206. Reasonable Additional Hours","description":"","frontmatter":{"title":"206. Reasonable Additional Hours","eba":"Mental Health Services 2024-2028","topics":["hours","overtime"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/hours-of-work/206-reasonable-additional-hours.md","filePath":"ebas/mental-health/management-admin/hours-of-work/206-reasonable-additional-hours.md"}'),n={name:"ebas/mental-health/management-admin/hours-of-work/206-reasonable-additional-hours.md"};function s(i,e,l,h,d,p){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_206-reasonable-additional-hours" tabindex="-1">206. Reasonable Additional Hours <a class="header-anchor" href="#_206-reasonable-additional-hours" aria-label="Permalink to &quot;206. Reasonable Additional Hours&quot;">​</a></h1><p><strong>206.1</strong> Subject to clause 206.2, an Employer may require an Employee to work reasonable additional hours at the appropriate overtime rate as defined in clause 203 (Overtime) of Section 5.</p><p><strong>206.2</strong> An Employee may refuse to work overtime in circumstances where the working of such overtime would result in the Employee working hours which are unreasonable having regard to:</p><p><strong>(a)</strong> any risk to Employee health and safety arising from the additional hours</p><p><strong>(b)</strong> the Employee&#39;s personal circumstances, including family responsibilities</p><p><strong>(c)</strong> the needs of the workplace or enterprise in which the Employee is employed</p><p><strong>(d)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects an expectation of, working additional hours</p><p><strong>(e)</strong> the notice (if any) given by the Employer of the overtime and by the Employee of their intention to refuse it</p><p><strong>(f)</strong> the usual patterns of work in the industry, or the part of the industry, in which the Employee works</p><p><strong>(g)</strong> the nature of the Employee’s role, and the Employee’s level of responsibility</p><p><strong>(h)</strong> whether the additional hours are in accordance with an averaging arrangement agreed to by the Employer and Employee under <a href="/eba/ebas/mental-health/management-admin/hours-of-work/199-hours-of-work.html">clause 199</a>[220] (Hours of Work); and</p><p><strong>(i)</strong> any other relevant matter.</p>',12)])])}const c=o(n,[["render",s]]);export{u as __pageData,c as default};
